'use client';

import React, { useState } from 'react';

const App = () => {
  const [todos, setTodos] = useState([
    { id: 1, text: 'Write a new blog post.', completed: false },
    { id: 2, text: 'Pick up laundry.', completed: false },
    { id: 3, text: 'Die.', completed: false },
  ]);
  const [inputValue, setInputValue] = useState('');

  const handleAddTodo = () => {
    if (inputValue.trim()) {
      setTodos([...todos, { id: Date.now(), text: inputValue, completed: false }]);
      setInputValue('');
    }
  };

  const toggleTodo = (id) => {
    setTodos(todos.map(todo => 
      todo.id === id ? { ...todo, completed: !todo.completed } : todo
    ));
  };

  return (
    <div className="min-h-screen bg-[#1a1a3a] flex justify-center font-sans">
      <div className="w-full max-w-[600px] bg-[#f0efef] min-h-screen flex flex-col items-center pt-8 px-10">

        {/* Header */}
        <div className="w-fit border border-black bg-white px-10 py-4 mb-8 text-center shadow-sm">
          <h1 className="text-[42px] text-[#333] leading-none">Another ToDo App</h1>
        </div>

        {/* Input Area */}
        <div className="w-full flex mb-8">
          <input
            type="text"
            className="flex-grow border border-gray-300 px-3 py-2.5 outline-none text-gray-700 text-lg"
            placeholder="Add a ToDo"
            value={inputValue}
            onChange={(e) => setInputValue(e.target.value)}
            onKeyPress={(e) => e.key === 'Enter' && handleAddTodo()}
          />
          <button
            onClick={handleAddTodo}
            className="bg-[#007bff] text-white px-10 py-2.5 text-lg font-medium hover:bg-[#0069d9] transition-colors"
          >
            Add
          </button>
        </div>

        {/* ToDo List */}
        <div className="w-full flex flex-col gap-4">
          {todos.map((todo) => (
            <div
              key={todo.id}
              className="flex items-center gap-3 bg-white p-4 border border-gray-200 shadow-[0_2px_4px_rgba(0,0,0,0.05)]"
            >
              <input
                type="checkbox"
                checked={todo.completed}
                onChange={() => toggleTodo(todo.id)}
                className="w-4 h-4 cursor-pointer accent-[#007bff]"
              />
              <span className={`text-[19px] text-[#333] ${todo.completed ? 'line-through text-gray-400' : ''}`}>
                {todo.text}
              </span>
            </div>
          ))}
        </div>

      </div>
    </div>
  );
};

export default App;
