```javascript
import React, { useState } from 'react';

const INITIAL_TASKS = [
  { id: 'todo-0', name: 'Eat', completed: true },
  { id: 'todo-1', name: 'Sleep', completed: false },
  { id: 'todo-2', name: 'Repeat', completed: false },
];

const FILTER_MAP = {
  All: () => true,
  Active: (task) => !task.completed,
  Completed: (task) => task.completed,
};

const FILTER_NAMES = Object.keys(FILTER_MAP);

export default function TodoMatic() {
  const [tasks, setTasks] = useState(INITIAL_TASKS);
  const [filter, setFilter] = useState('All');
  const [name, setName] = useState('');

  function toggleTaskCompleted(id) {
    const updatedTasks = tasks.map((task) => {
      if (id === task.id) {
        return { ...task, completed: !task.completed };
      }
      return task;
    });
    setTasks(updatedTasks);
  }

  function deleteTask(id) {
    const remainingTasks = tasks.filter((task) => id !== task.id);
    setTasks(remainingTasks);
  }

  function addTask(name) {
    if (!name.trim()) return;
    const newTask = { id: `todo-${Math.random()}`, name, completed: false };
    setTasks([...tasks, newTask]);
    setName('');
  }

  function handleSubmit(e) {
    e.preventDefault();
    addTask(name);
  }

  const taskList = tasks
    .filter(FILTER_MAP[filter])
    .map((task) => (
      <Todo
        id={task.id}
        name={task.name}
        completed={task.completed}
        key={task.id}
        toggleTaskCompleted={toggleTaskCompleted}
        deleteTask={deleteTask}
      />
    ));

  const filterList = FILTER_NAMES.map((name) => (
    <FilterButton
      key={name}
      name={name}
      isPressed={name === filter}
      setFilter={setFilter}
    />
  ));

  const tasksNoun = taskList.length !== 1 ? 'tasks' : 'task';
  const headingText = `${taskList.length} ${tasksNoun} remaining`;

  return (
    <div style={styles.pageWrapper}>
      <div style={styles.container}>
        <h1 style={styles.title}>TodoMatic</h1>
        <form onSubmit={handleSubmit} style={styles.form}>
          <h2 style={styles.labelWrapper}>
            <label htmlFor="new-todo-input" style={styles.label}>
              What needs to be done?
            </label>
          </h2>
          <input
            type="text"
            id="new-todo-input"
            style={styles.input}
            name="text"
            autoComplete="off"
            value={name}
            onChange={(e) => setName(e.target.value)}
          />
          <button type="submit" style={styles.addButton}>
            Add
          </button>
        </form>
        <div style={styles.filters}>
          {filterList}
        </div>
        <h2 style={styles.listHeading}>{headingText}</h2>
        <ul role="list" style={styles.todoList} aria-labelledby="list-heading">
          {taskList}
        </ul>
      </div>
    </div>
  );
}

function FilterButton(props) {
  return (
    <button
      type="button"
      style={{
        ...styles.filterBtn,
        border: props.isPressed ? '1px solid #000' : '1px solid #d3d3d3',
      }}
      aria-pressed={props.isPressed}
      onClick={() => props.setFilter(props.name)}
    >
      <span>{props.name}</span>
    </button>
  );
}

function Todo(props) {
  return (
    <li style={styles.todoItem}>
      <div style={styles.stackSmall}>
        <div style={styles.checkboxGroup}>
          <div 
            style={styles.checkboxContainer} 
            onClick={() => props.toggleTaskCompleted(props.id)}
          >
            <div style={styles.customCheckbox}>
               {props.completed && (
                 <svg viewBox="0 0 24 24" style={styles.checkmark}>
                   <polyline points="20 6 9 17 4 12" />
                 </svg>
               )}
            </div>
            <label style={styles.todoLabel} htmlFor={props.id}>
              {props.name}
            </label>
          </div>
        </div>
        <div style={styles.btnGroup}>
          <button type="button" style={styles.editBtn}>
            Edit
          </button>
          <button
            type="button"
            style={styles.deleteBtn}
            onClick={() => props.deleteTask(props.id)}
          >
            Delete
          </button>
        </div>
      </div>
    </li>
  );
}

